// Rateio proporcional ao salário — lógica pura do dashboard da reunião familiar.
// TDD em rateio.test.js. Módulo Node consumido pelo runner (não é Code node n8n).
// Implementa gstack/specs/dashboard-reuniao-familiar.md.

/** Remove acento e caixa para comparar categorias/nomes (Deposito ~ Depósito). */
function normalizar(s) {
  return String(s == null ? "" : s)
    .normalize("NFD").replace(/[̀-ͯ]/g, "").trim().toLowerCase();
}

const arred = (n) => Math.round(n * 100) / 100;

/**
 * Valor da planilha → número. Defesa contra `valor` gravado como TEXTO (ex.: o nó
 * googleSheets em USER_ENTERED + locale pt_BR pode coagir "1011.87" a texto). Aceita
 * número nativo, "1011.87" (ponto decimal), BR "1.011,56"/"1011,56" e "R$ 1.234,56".
 * Lixo/vazio → 0 (nunca NaN — NaN envenenaria a soma inteira do relatório).
 */
function valorNum(v) {
  if (typeof v === "number") return Number.isFinite(v) ? v : 0;
  if (v === null || v === undefined) return 0;
  let s = String(v).trim().replace(/^R\$\s*/i, "");
  if (s === "") return 0;
  if (s.includes(",")) s = s.replace(/\./g, "").replace(",", ".");        // BR: ponto=milhar, vírgula=decimal
  else if ((s.match(/\./g) || []).length > 1) s = s.replace(/\./g, "");   // só pontos múltiplos = milhar
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

/**
 * Categorias de transferência interna — movimentação entre contas próprias
 * (ex.: pagar a fatura do cartão, resgate/aplicação, Pix para si mesmo). NÃO são
 * consumo nem receita: o gasto real já está nas compras da fatura (origem=cartao)
 * e contá-las de novo no extrato duplicaria. O parser resolve "Pagamento/Retirada"
 * para uma destas conforme a direção (entrada→Pagamento, saída→Retirada).
 */
const CATEGORIAS_TRANSFERENCIA = new Set(["pagamento", "retirada"]);
function ehTransferencia(categoria) {
  return CATEGORIAS_TRANSFERENCIA.has(normalizar(categoria));
}

/** salarios: {pessoa: salario} ou [{pessoa, salario}] → {pessoa: proporção}. */
function proporcoes(salarios) {
  const pares = Array.isArray(salarios)
    ? salarios.map((s) => [s.pessoa, Number(s.salario)])
    : Object.entries(salarios).map(([p, v]) => [p, Number(v)]);
  const total = pares.reduce((s, [, v]) => s + v, 0);
  if (!(total > 0)) throw new Error("soma dos salários deve ser > 0 (configurar aba Salários)");
  const out = {};
  for (const [p, v] of pares) out[p] = v / total;
  return out;
}

/**
 * Data da planilha → "MM/YYYY" | null. Aceita os três formatos que o nó de
 * leitura pode devolver (valueRenderOption=UNFORMATTED_VALUE):
 *   - "DD/MM/YYYY" (string) ;
 *   - "YYYY-MM-DD" (string ISO) ;
 *   - serial do Sheets (número ou string só-dígitos): célula formatada como
 *     Data volta como dias desde 1899-12-30, não como string.
 */
function mesDe(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number" || (typeof v === "string" && /^\d+(\.\d+)?$/.test(v.trim()))) {
    const serial = Math.floor(Number(v));
    if (!Number.isFinite(serial) || serial <= 0) return null;
    const d = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
    return `${String(d.getUTCMonth() + 1).padStart(2, "0")}/${d.getUTCFullYear()}`;
  }
  const s = String(v).trim();
  let m;
  if ((m = /^\d{2}\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[1]}/${m[2]}`;
  if ((m = /^(\d{4})-(\d{2})-\d{2}/.exec(s))) return `${m[2]}/${m[1]}`;
  return null;
}

/** "MM/YYYY" → número YYYYMM comparável (ex.: "05/2026" → 202605); inválido → null. */
function mesParaNum(mes) {
  const m = /^(\d{2})\/(\d{4})$/.exec(String(mes == null ? "" : mes).trim());
  if (!m) return null;
  return Number(m[2]) * 100 + Number(m[1]);
}

/**
 * Pessoa dona de uma categoria exclusiva "Gastos {pessoa}", ou null. Despesa
 * exclusiva NÃO é dividida por salário: é cobrada 100% de quem é (decisão do Marcelo).
 */
function categoriaExclusivaDe(categoria, pessoas) {
  const c = normalizar(categoria);
  for (const p of pessoas) {
    if (c === "gastos " + normalizar(p)) return p;
  }
  return null;
}

/**
 * Movimentação PESSOAL (não é da casa): "Depósito para o/a {pessoa}" (entrada) e
 * "Saída para o/a {pessoa}" (saída). Dinheiro que passou pela conta mas é pessoal —
 * ex.: Pix de terceiros que era do Marcelo + o Pix que ele mandou de volta p/ si.
 * APARECE no fluxo de caixa (entradas/saídas), mas é NEUTRA ao rateio: não é
 * contribuição (pago) nem custo/dívida da casa (base/cota). Distingue-se de "Retirada"
 * (pgto de fatura / aplicação CDB), que é transferência excluída de tudo.
 */
function ehMovimentacaoPessoal(categoria) {
  const c = normalizar(categoria);
  return /^deposito para /.test(c) || /^saida para /.test(c);
}

/**
 * Núcleo do rateio sobre um conjunto JÁ filtrado de lançamentos (DRY entre rateioMes
 * e rateioAcumulado). `prop` = proporções por pessoa (de proporcoes()).
 * - base dividida = saídas confirmadas não-transferência, não-exclusivas e não-pessoais;
 * - exclusivo[p] = Σ saídas confirmadas "Gastos {p}" (100% da pessoa);
 * - cota[p] = base × prop[p] + exclusivo[p];   pago[p] = entradas "Depósito {p}";
 * - saldo = pago − cota;  acerto = cota − pago (positivo = a pessoa deve).
 * Movimentações pessoais ("Depósito/Saída para o ...") são IGNORADAS aqui (neutras).
 * Conservação: Σ cotas = base + Σ exclusivos = Σ saídas confirmadas não-transferência/pessoais.
 * @returns {{totalDespesas, cota, pago, saldo, acerto}}
 */
function calcularRateio(lancamentos, prop) {
  const pessoas = Object.keys(prop);
  const exclusivo = {};
  for (const p of pessoas) exclusivo[p] = 0;
  let base = 0;
  for (const l of lancamentos) {
    if (l.tipo !== "saída" || l.status !== "confirmado") continue;
    if (ehTransferencia(l.categoria) || ehMovimentacaoPessoal(l.categoria)) continue; // fora do rateio
    const dono = categoriaExclusivaDe(l.categoria, pessoas);
    if (dono) exclusivo[dono] = arred(exclusivo[dono] + valorNum(l.valor));
    else base = arred(base + valorNum(l.valor));
  }
  const totalDespesas = arred(base + pessoas.reduce((s, p) => s + exclusivo[p], 0));

  // Divide a base entre as pessoas; a ÚLTIMA absorve o resíduo de arredondamento para
  // garantir Σ(parte dividida) == base exatamente — sem dívida-fantasma de R$ 0,01 no
  // saldo cumulativo (que nunca quitaria). O exclusivo de cada um soma à parte dele.
  const parteBase = {};
  let alocado = 0;
  pessoas.forEach((p, idx) => {
    if (idx === pessoas.length - 1) parteBase[p] = arred(base - alocado);
    else { parteBase[p] = arred(base * prop[p]); alocado = arred(alocado + parteBase[p]); }
  });

  const cota = {}, pago = {}, saldo = {}, acerto = {};
  for (const p of pessoas) {
    cota[p] = arred(parteBase[p] + exclusivo[p]);
    const alvo = normalizar(`deposito ${p}`);
    pago[p] = arred(lancamentos
      .filter((l) => l.tipo === "entrada" && normalizar(l.categoria) === alvo)
      .reduce((s, l) => s + valorNum(l.valor), 0));
    saldo[p] = arred(pago[p] - cota[p]);
    acerto[p] = arred(cota[p] - pago[p]);
  }
  return { totalDespesas, cota, pago, saldo, acerto };
}

/**
 * Rateio do mês (`mes` = "MM/YYYY"). Visão de um único mês (usada no relatório).
 * @returns {{mes, totalDespesas, proporcoes, cota, pago, saldo, acerto}}
 */
function rateioMes(lancamentos, salarios, mes) {
  const prop = proporcoes(salarios);
  const doMes = lancamentos.filter((l) => mesDe(l.data_competencia) === mes);
  return { mes, proporcoes: prop, ...calcularRateio(doMes, prop) };
}

/**
 * Rateio CUMULATIVO: todos os meses com `mesDe ≤ mesAte`. Detecta dívida acumulada
 * de meses anteriores (decisão do Marcelo). Lançamentos com data ilegível
 * (`mesDe===null`) são descartados — nunca comparados.
 * @returns {{mesAte, acumulado:true, totalDespesas, proporcoes, cota, pago, saldo, acerto}}
 */
function rateioAcumulado(lancamentos, salarios, mesAte) {
  const prop = proporcoes(salarios);
  const ate = mesParaNum(mesAte);
  const ateOuAntes = lancamentos.filter((l) => {
    const m = mesParaNum(mesDe(l.data_competencia));
    return m !== null && (ate === null || m <= ate);
  });

  const mesesSet = new Set();
  for (const l of ateOuAntes) {
    const m = mesDe(l.data_competencia);
    if (m) mesesSet.add(m);
  }
  const mesesOrdenados = [...mesesSet].sort((a, b) => mesParaNum(a) - mesParaNum(b));

  const pessoas = Object.keys(prop);
  // FONTE ÚNICA: os totais do card são a SOMA mês-a-mês (mesmo cálculo do histórico do
  // modal). Antes o card vinha de um calcularRateio agregado separado, que podia divergir
  // da soma do modal em centavos (resíduo de arredondamento absorvido 1× vs N×). Agora o
  // card == última linha de saldoAcumulado do histórico, sempre.
  const cota = {}, pago = {}, saldo = {}, acerto = {};
  for (const p of pessoas) { cota[p] = 0; pago[p] = 0; saldo[p] = 0; acerto[p] = 0; }
  let totalDespesas = 0;
  const historico = [];

  for (const m of mesesOrdenados) {
    const doMes = lancamentos.filter((l) => mesDe(l.data_competencia) === m);
    const rMes = calcularRateio(doMes, prop);

    totalDespesas = arred(totalDespesas + rMes.totalDespesas);
    for (const p of pessoas) {
      cota[p] = arred(cota[p] + rMes.cota[p]);
      pago[p] = arred(pago[p] + rMes.pago[p]);
      saldo[p] = arred(saldo[p] + rMes.saldo[p]);
      acerto[p] = arred(cota[p] - pago[p]);
    }

    const exclusivoMes = {};
    for (const p of pessoas) {
      exclusivoMes[p] = 0;
      for (const l of doMes) {
        if (l.tipo === "saída" && l.status === "confirmado"
          && categoriaExclusivaDe(l.categoria, pessoas) === p) {
          exclusivoMes[p] = arred(exclusivoMes[p] + valorNum(l.valor));
        }
      }
    }

    historico.push({
      mes: m,
      totalDespesas: rMes.totalDespesas,
      cota: rMes.cota,
      exclusivo: exclusivoMes,
      pago: rMes.pago,
      saldo: rMes.saldo,
      saldoAcumulado: { ...saldo }, // == card (soma corrente) — modal e card sempre batem
    });
  }

  return { mesAte, acumulado: true, proporcoes: prop, totalDespesas, cota, pago, saldo, acerto, historico };
}


// Agregações do dashboard da reunião familiar — lógica pura. TDD em dashboard.test.js.
// Módulo Node consumido pelo runner (não é Code node n8n).
// Implementa gstack/specs/dashboard-reuniao-familiar.md.
/** Saídas confirmadas do mês agrupadas por categoria, ordenadas desc. */
function gastosPorCategoria(lancamentos, mes) {
  const acc = new Map();
  for (const l of lancamentos) {
    if (l.tipo !== "saída" || l.status !== "confirmado" || mesDe(l.data_competencia) !== mes) continue;
    if (ehTransferencia(l.categoria) || ehMovimentacaoPessoal(l.categoria)) continue; // só gastos da casa
    acc.set(l.categoria, (acc.get(l.categoria) || 0) + valorNum(l.valor));
  }
  return [...acc.entries()]
    .map(([categoria, total]) => ({ categoria, total: arred(total) }))
    .sort((a, b) => b.total - a.total);
}

/**
 * Totais confirmados do mês: saídas, entradas, saldo. É a visão de FLUXO DE CAIXA — inclui
 * movimentações pessoais ("Depósito/Saída para o ..."), que o usuário quer ver entrando/saindo.
 * Só exclui transferências internas (pgto de fatura / aplicação CDB), que dobrariam contagem.
 * (Logo, `saidas` pode ser > Σ gastosPorCategoria, que mostra só os gastos da casa.)
 */
function totaisMes(lancamentos, mes) {
  const soma = (tipo) => arred(lancamentos
    .filter((l) => l.tipo === tipo && l.status === "confirmado" && mesDe(l.data_competencia) === mes
      && !ehTransferencia(l.categoria))
    .reduce((s, l) => s + valorNum(l.valor), 0));
  const saidas = soma("saída");
  const entradas = soma("entrada");
  return { saidas, entradas, saldo: arred(entradas - saidas) };
}

/**
 * Previsão do próximo mês (`mes` = "MM/YYYY"): parcelas já lançadas (saídas
 * previstas do mês) + projeção das contas fixas ativas cuja categoria ainda NÃO
 * aparece no mês. Depósitos previstos = total × proporção (regra do Marcelo).
 * @param {{nome, valor_esperado, ativo}[]} contasFixas aba Contas Fixas
 * @returns {{gastos:{fixas,parcelas,total}, depositosPrevistos:{[pessoa]:number}}}
 */
function previsaoProximoMes(lancamentos, contasFixas, salarios, mes, faturaAbertaRows) {
  const prop = proporcoes(salarios);
  const pessoas = Object.keys(prop);

  // 1. Gastos fixos ativos
  const fixas = arred((contasFixas || [])
    .filter((f) => normalizar(f.ativo) === "sim")
    .reduce((s, f) => s + valorNum(f.valor_esperado), 0));

  // 2. Fatura aberta fechada
  const faFechadas = (faturaAbertaRows || []).filter((r) => normalizar(r.status) === "fechado");
  const faturaTotal = arred(faFechadas.reduce((s, r) => s + valorNum(r.valor), 0));

  // 3. Gastos exclusivos/pessoais na fatura aberta
  const exclusivoFatura = {};
  for (const p of pessoas) {
    exclusivoFatura[p] = 0;
  }
  for (const r of faFechadas) {
    const dono = categoriaExclusivaDe(r.categoria_c6, pessoas);
    if (dono) {
      exclusivoFatura[dono] = arred(exclusivoFatura[dono] + valorNum(r.valor));
    }
  }
  const exclusivoFaturaTotal = arred(pessoas.reduce((s, p) => s + exclusivoFatura[p], 0));

  // 4. Base comum (compartilhada)
  const faturaBase = arred(faturaTotal - exclusivoFaturaTotal);
  const totalPrevistoBase = arred(fixas + faturaBase);

  // 5. Rateio da base proporcional ao salário (conservação de resíduo de arredondamento)
  const parteBase = {};
  let alocado = 0;
  pessoas.forEach((p, idx) => {
    if (idx === pessoas.length - 1) {
      parteBase[p] = arred(totalPrevistoBase - alocado);
    } else {
      parteBase[p] = arred(totalPrevistoBase * prop[p]);
      alocado = arred(alocado + parteBase[p]);
    }
  });

  // 6. Depósito previsto = cota base proporcional + gastos exclusivos individuais
  const depositosPrevistos = {};
  for (const p of pessoas) {
    depositosPrevistos[p] = arred(parteBase[p] + exclusivoFatura[p]);
  }

  // 7. Detalhes
  const detalhes = [];
  for (const f of contasFixas || []) {
    if (normalizar(f.ativo) === "sim") {
      detalhes.push({ categoria: f.nome, valor: valorNum(f.valor_esperado) });
    }
  }
  if (faturaTotal > 0) {
    detalhes.push({ categoria: "Fatura Cartão C6", valor: faturaTotal });
  }

  const total = arred(fixas + faturaTotal);

  return { gastos: { fixas, parcelas: faturaTotal, total }, detalhes, depositosPrevistos };
}

/**
 * Comprometido futuro (v2): fatura aberta do ciclo corrente + projeção das parcelas.
 * Prospectivo a partir de `hojeISO` (YYYY-MM-DD) — independe do seletor de mês. Bloco
 * separado da previsão (anti-dupla-contagem): a projeção é derivada da aba `Parcelas`,
 * nunca de `Lançamentos`.
 * @param {object[]} faturaAbertaRows linhas da aba FaturaAberta (A:G)
 * @param {object[]} parcelasRows linhas da aba Parcelas (A:E) — ciclo_referencia em serial
 * @param {object[]} configRows aba Config (chave|valor) — comprometido_horizonte (default 6)
 * @returns {{faturaAberta:{ciclo,total,status,porCategoria}|null, parcelas:{vencimento,total}[], horizonte:number}}
 */
function comprometidoFuturo(faturaAbertaRows, parcelasRows, configRows, hojeISO) {
  let horizonte = 6;
  const cfg = (configRows || []).find((r) => normalizar(r.chave) === "comprometido_horizonte");
  if (cfg && Math.floor(Number(cfg.valor)) > 0) horizonte = Math.floor(Number(cfg.valor));

  // Fatura aberta: só status='fechado' (R3 — rascunho/não-fechado fora do dashboard).
  let faFechadas = (faturaAbertaRows || []).filter((r) => normalizar(r.status) === "fechado");
  let faturaAberta = null;
  if (faFechadas.length) {
    // A aba é clear+write de um único ciclo; mas se sobrarem 'fechado' de ciclos diferentes
    // (reseed parcial), ancora no ciclo mais recente — evita total e rótulo divergirem.
    const ciclos = [...new Set(faFechadas.map((r) => normalizarCiclo(r.ciclo)))]
      .filter(Boolean)
      .sort((a, b) => -(mesesEntreVencimentos(a, b) || 0)); // crescente (mesesEntre = b−a)
    const ciclo = ciclos[ciclos.length - 1];
    faFechadas = faFechadas.filter((r) => normalizarCiclo(r.ciclo) === ciclo);
    const total = arred(faFechadas.reduce((s, r) => s + valorNum(r.valor), 0));
    const catMap = new Map();
    for (const r of faFechadas) {
      const c = (r.categoria_c6 && String(r.categoria_c6).trim()) || "Outros";
      catMap.set(c, (catMap.get(c) || 0) + valorNum(r.valor));
    }
    const porCategoria = [...catMap.entries()]
      .map(([categoria, t]) => ({ categoria, total: arred(t) }))
      .sort((a, b) => b.total - a.total);
    faturaAberta = { ciclo, total, status: "fechado", porCategoria };
  }

  // Âncora = max(ciclo da fatura aberta, vencimento do ciclo aberto de hoje) — Q2.
  // Se vencHoje falhar (hoje malformado), usa o ciclo da fatura aberta como âncora.
  const vencHoje = vencimentoCicloAberto(hojeISO);
  let ancora = vencHoje;
  if (faturaAberta && (!vencHoje || mesesEntreVencimentos(vencHoje, faturaAberta.ciclo) > 0)) {
    ancora = faturaAberta.ciclo;
  }

  const parcelaRows = (parcelasRows || []).map((r) => ({
    estabelecimento: r.estabelecimento,
    valor: valorNum(r.valor),
    M: Number(r.M),
    N_no_seed: Number(r.N_no_seed),
    ciclo_referencia: normalizarCiclo(r.ciclo_referencia),
  }));
  const parcelas = ancora ? projetarComprometido(parcelaRows, ancora, horizonte) : [];
  return { faturaAberta, parcelas, horizonte };
}


// Relatório mensal financeiro (Telegram) — lógica pura. TDD em relatorio.test.js.
// Implementa gstack/plans/relatorio-mensal.md. Reusa dashboard.js e rateio.js (DRY).
const MESES = ["janeiro", "fevereiro", "março", "abril", "maio", "junho",
  "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"];

/** "MM/YYYY" → "março/2025" (fallback ao próprio valor). */
function nomeMes(mes) {
  const m = /^(\d{2})\/(\d{4})$/.exec(String(mes));
  return m ? `${MESES[Number(m[1]) - 1] || m[1]}/${m[2]}` : String(mes);
}

/** Moeda BR: 1253 → "R$ 1.253,00" (sempre módulo; sinal tratado pelo chamador). */
function brl(n) {
  const [int, dec] = Math.abs(arred(Number(n))).toFixed(2).split(".");
  return `R$ ${int.replace(/\B(?=(\d{3})+(?!\d))/g, ".")},${dec}`;
}

/** Escapa para parse_mode HTML do Telegram. */
function esc(s) {
  return String(s == null ? "" : s)
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

/**
 * Contas fixas a pagar no mês vigente (`mesFixos` = "MM/YYYY"), com datas de
 * vencimento. Mensais: 1 linha cada (ordenada por dia). Empregada (semanal):
 * agrupada em 1 linha "sextas". Fatura do cartão: Σ origem="cartao" cuja
 * data_competencia (= vencimento) cai no mês; vencimento = Config.cartao_vencimento_dia.
 * @returns {{linhas: {nome,valor,vencimento,obs?}[], subtotal: number}}
 */
function contasFixasDoMes(contasFixas, lancamentos, config, mesFixos) {
  const linhas = [];
  for (const f of contasFixas || []) {
    if (normalizar(f.ativo) !== "sim") continue;
    const dia = Number(f.dia_vencimento);
    const numerico = Number.isFinite(dia) && String(f.dia_vencimento).trim() !== "";
    linhas.push({
      nome: f.nome,
      valor: arred(valorNum(f.valor_esperado)),
      vencimento: numerico ? `dia ${dia}` : "sextas",
      _dia: numerico ? dia : Infinity,
    });
  }

  const diaCartao = Number((config || {}).cartao_vencimento_dia) || 10;
  // Fatura LÍQUIDA do mês: saídas menos créditos/estornos (entrada). Antes somava
  // entrada como positivo (inflava) e não excluía transferências (ex.: pagamento
  // da própria fatura, se rotulado). Espelha o resumo.total do parser-cartao.
  const fatura = arred((lancamentos || [])
    .filter((l) => normalizar(l.origem) === "cartao" && !ehTransferencia(l.categoria)
      && mesDe(l.data_competencia) === mesFixos)
    .reduce((s, l) => s + (l.tipo === "entrada" ? -valorNum(l.valor) : valorNum(l.valor)), 0));
  const cartao = { nome: "Cartão C6", valor: fatura, vencimento: `dia ${diaCartao}`, _dia: diaCartao };
  if (fatura === 0) cartao.obs = "fatura ainda não importada";
  linhas.push(cartao);

  linhas.sort((a, b) => a._dia - b._dia);
  const subtotal = arred(linhas.reduce((s, l) => s + l.valor, 0));
  for (const l of linhas) delete l._dia;
  return { linhas, subtotal };
}

/** Idempotência do cron: false se já existe `relatorio_enviado` desse mesGastos. */
function deveEnviarCron(logs, mesGastos) {
  return !(logs || []).some(
    (l) => l.acao === "relatorio_enviado" && String(l.valor_anterior) === mesGastos);
}

/**
 * Monta o texto HTML do relatório.
 * @param {{lancamentos, contasFixas, salarios, config}} dados
 * @param {{mesGastos, mesFixos, urlPlanilha}} opts
 * @returns {{texto: string}}
 */
function montarRelatorio(dados, opts) {
  const { lancamentos, contasFixas, salarios, config } = dados;
  const { mesGastos, mesFixos, urlPlanilha } = opts;
  const L = [];

  const tot = totaisMes(lancamentos, mesGastos);
  L.push(`📊 <b>Relatório — ${esc(nomeMes(mesGastos))}</b>`, "");
  L.push("<b>Gastos do mês</b>");
  L.push(`Saídas: ${brl(tot.saidas)}`);
  L.push(`Entradas: ${brl(tot.entradas)}`);
  L.push(`Saldo: ${brl(tot.saldo)}${tot.saldo < 0 ? " (negativo)" : ""}`);

  const cats = gastosPorCategoria(lancamentos, mesGastos);
  if (cats.length) {
    L.push("", "<b>Por categoria</b>");
    for (const c of cats.slice(0, 5)) L.push(`• ${esc(c.categoria)}: ${brl(c.total)}`);
    const resto = arred(cats.slice(5).reduce((s, c) => s + c.total, 0));
    if (resto > 0) L.push(`• Outras: ${brl(resto)}`);
  }

  L.push("", "<b>Rateio</b>");
  try {
    const r = rateioMes(lancamentos, salarios, mesGastos);
    for (const p of Object.keys(r.acerto)) {
      const a = r.acerto[p];
      const txt = a > 0 ? `deve ${brl(a)}` : a < 0 ? `crédito ${brl(a)}` : "quitado";
      L.push(`• ${esc(p)}: ${txt}`);
    }
  } catch (e) {
    L.push("⚠️ rateio indisponível (configure a aba Salários)");
  }

  const fix = contasFixasDoMes(contasFixas, lancamentos, config, mesFixos);
  L.push("", `<b>Contas fixas — ${esc(nomeMes(mesFixos))}</b>`);
  for (const l of fix.linhas) {
    const obs = l.obs ? ` (${esc(l.obs)})` : "";
    L.push(`• ${esc(l.nome)} — ${brl(l.valor)} — ${esc(l.vencimento)}${obs}`);
  }
  L.push(`Subtotal: ${brl(fix.subtotal)}`);

  if (urlPlanilha) L.push("", `🔗 <a href="${esc(urlPlanilha)}">Dashboard</a>`);

  return { texto: L.join("\n") };
}



// ── Glue (cron): fecha o mês anterior; contas fixas do mês vigente ──
const vr = ($json.valueRanges || []);
const paraObjetos = (idx) => {
  const v = (vr[idx] && vr[idx].values) || [];
  if (v.length < 2) return [];
  const h = v[0].map(String);
  return v.slice(1).map((linha) => {
    const o = {};
    h.forEach((c, j) => { o[c] = linha[j] !== undefined ? linha[j] : ''; });
    return o;
  });
};
const mesVigente = (iso) => { const [y, m] = iso.split('-'); return m + '/' + y; };
const mesAnterior = (iso) => { let [y, m] = iso.split('-').map(Number); m -= 1;
  if (m === 0) { m = 12; y -= 1; } return String(m).padStart(2, '0') + '/' + y; };
const cfgDict = (rows) => { const o = {}; for (const r of rows) o[r.chave] = r.valor; return o; };
const urlPlanilha = 'https://docs.google.com/spreadsheets/d/' + $env.GOOGLE_SHEETS_ID + '/edit';
const hoje = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Sao_Paulo' });
const lanc = paraObjetos(0), fixas = paraObjetos(1), sal = paraObjetos(2), cfg = cfgDict(paraObjetos(3));
const logs = paraObjetos(4);
const mesGastos = mesAnterior(hoje), mesFixos = mesVigente(hoje);
if (!deveEnviarCron(logs, mesGastos)) return []; // já enviou este mês → no-op
const { texto } = montarRelatorio({ lancamentos: lanc, contasFixas: fixas, salarios: sal, config: cfg },
  { mesGastos, mesFixos, urlPlanilha });
return [{ json: { texto, log: { timestamp: new Date().toISOString(),
  acao: 'relatorio_enviado', entidade: 'Relatorio', valor_anterior: mesGastos,
  valor_novo: '', origem: 'relatorio-mensal' } } }];

const envios = $input.all();
return $('Montar').all()
  .filter((i, idx) => !(envios[idx] && envios[idx].json && envios[idx].json.error))
  .map((i) => ({ json: i.json.log }));
